const body = $input.first().json.body || $input.first().json;
const ticketUrl = body.ticketUrl || '';
const ticketKey = body.ticketKey || '';

if (!ticketKey) {
  const m = ticketUrl.match(/browse\/([A-Z]+-\d+)/i);
  if (!m) throw new Error('无法解析 Ticket ID，请检查 Jira URL 格式: ' + ticketUrl);
}

const key = (ticketKey || ticketUrl.match(/browse\/([A-Z]+-\d+)/i)[1]).toUpperCase();
const projectKey = key.split('-')[0];

return [{
  json: {
    ticketUrl,
    ticketKey: key,
    projectKey,
    jiraBase: body.jiraBase || 'carsome.atlassian.net',
    repo: body.repo || ''
  }
}];

const issue     = $input.first().json;
const prevData  = $('解析 Ticket').first().json;

const fields       = issue.fields;
const summary      = fields.summary || '';
const description  = fields.description;
const parentKey    = fields.parent?.key || null;
const team         = fields.customfield_10001;
const country      = fields.customfield_10752;
const projectKey   = fields.project?.key || prevData.projectKey;

// 生成分支名：lowercase，下划线，最多 5 个英文词
function toBranchName(text) {
  return text
    .replace(/\[.*?\]/g, '')         // 去除 [FE] [BE] 等前缀
    .replace(/[^a-zA-Z0-9\s]/g, ' ') // 非字母数字转空格
    .toLowerCase()
    .trim()
    .split(/\s+/)
    .filter(Boolean)
    .slice(0, 5)
    .join('_')
    .replace(/_+/g, '_')
    .substring(0, 40);
}

const branchDesc = toBranchName(summary);
const branch     = 'feature_cxh_' + branchDesc;

// 新标题加 [FE] 前缀
const newSummary = /^\[FE\]/i.test(summary) ? summary : '[FE] ' + summary;

// 构造 ADF 描述：在原描述 content 数组头部插入「原始需求：xxx」段落
const originParagraph = {
  type: 'paragraph',
  content: [{
    type: 'text',
    text: '原始需求：' + prevData.ticketKey,
    marks: [{ type: 'strong' }]
  }]
};

let newDescription;
if (description && Array.isArray(description.content)) {
  newDescription = {
    ...description,
    content: [originParagraph, ...description.content]
  };
} else {
  newDescription = {
    type: 'doc',
    version: 1,
    content: [originParagraph]
  };
}

// 构造 additional_fields
const extraFields = {};
if (parentKey) { extraFields.parent = { key: parentKey }; }
if (team)      { extraFields.customfield_10001 = team; }
if (country)   { extraFields.customfield_10752 = country; }

const newIssueBody = {
  fields: {
    project:    { key: projectKey },
    issuetype:  { name: '任务' },
    summary:    newSummary,
    description: newDescription,
    assignee:   { accountId: '6047596a43eac6006f6c3897' },
    ...extraFields
  }
};

return [{
  json: {
    ...prevData,
    originalSummary:   summary,
    originalTicketUrl: 'https://' + prevData.jiraBase + '/browse/' + prevData.ticketKey,
    parentKey,
    branch,
    newSummary,
    newIssueBody
  }
}];

const createdIssue = $input.first().json;
const prevData     = $('准备新 Issue 数据').first().json;

const newIssueKey = createdIssue.key;
if (!newIssueKey) {
  throw new Error('创建 Jira Issue 失败: ' + JSON.stringify(createdIssue));
}

return [{
  json: {
    ...prevData,
    newIssueKey,
    newTicketUrl: 'https://' + prevData.jiraBase + '/browse/' + newIssueKey
  }
}];

const transitionsResp = $input.first().json;
const transitions     = transitionsResp.transitions || [];
const merged          = $('合并创建结果').first().json;

const inProgress = transitions.find(t =>
  /in.?progress|进行中|正在进行/i.test(t.name)
);

if (!inProgress) {
  console.log('Available transitions:', transitions.map(t => t.name));
}

return [{
  json: {
    ...merged,
    transitionId: inProgress?.id || null,
    availableTransitions: transitions.map(t => t.name)
  }
}];

